import{_ as e,b as a,e as s,al as n}from"./chunks/framework.tsjOpNIE.js";const l="/CoreFront-EndConcepts/multiColumnFirst.png",o="/CoreFront-EndConcepts/multiColumnSecond.png",i="/CoreFront-EndConcepts/multiColumnThird.png",y=JSON.parse('{"title":"多列布局 (CSS Multi-column Layout)","description":"","frontmatter":{},"headers":[],"relativePath":"css/multiColumn.md","filePath":"css/multiColumn.md","lastUpdated":1772787829000}'),d={name:"css/multiColumn.md"};function r(c,t,h,g,p,k){return a(),s("div",null,[...t[0]||(t[0]=[n('<h1 id="多列布局-css-multi-column-layout" tabindex="-1">多列布局 (CSS Multi-column Layout) <a class="header-anchor" href="#多列布局-css-multi-column-layout" aria-label="Permalink to &quot;多列布局 (CSS Multi-column Layout)&quot;">​</a></h1><p>CSS Multi-column 模块的核心逻辑是将一个容器内的内容（文本、图片等）自动拆分到多列中，就像报纸排版一样。</p><h2 id="_1-容器属性-api-container-properties" tabindex="-1">1. 容器属性 API (Container Properties) <a class="header-anchor" href="#_1-容器属性-api-container-properties" aria-label="Permalink to &quot;1. 容器属性 API (Container Properties)&quot;">​</a></h2><p>这些属性必须设置在<strong>父容器</strong>上。</p><h3 id="_1-1-定义列的核心属性" tabindex="-1">1.1 定义列的核心属性 <a class="header-anchor" href="#_1-1-定义列的核心属性" aria-label="Permalink to &quot;1.1 定义列的核心属性&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">属性</th><th style="text-align:left;">语法 / 示例</th><th style="text-align:left;">详细逻辑</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>column-count</code></strong></td><td style="text-align:left;"><code>&lt;integer&gt; | auto</code><br><code>column-count: 3;</code></td><td style="text-align:left;"><strong>强制分列数</strong>。<br>浏览器会根据容器宽度自动计算每一列的宽度。<br>如果不指定宽度，列宽会随容器伸缩。</td></tr><tr><td style="text-align:left;"><strong><code>column-width</code></strong></td><td style="text-align:left;"><code>&lt;length&gt; | auto</code><br><code>column-width: 200px;</code></td><td style="text-align:left;"><strong>理想（最小）列宽</strong>。<br>浏览器会计算：<code>容器宽 / 200px</code> 能放下几列？<br>例如容器 500px，设为 200px，则显示 2 列（每列 250px），剩余空间均分。</td></tr><tr><td style="text-align:left;"><strong><code>columns</code></strong></td><td style="text-align:left;"><code>[width] || [count]</code><br><code>columns: 3 200px;</code></td><td style="text-align:left;"><strong>简写属性</strong>。<br>表示：<strong>“最多 3 列，且每一列不能小于 200px”</strong>。<br>这是一个非常灵活的响应式写法。</td></tr></tbody></table><p><img src="'+l+'" alt="Logo" data-zoomable="true"></p><h3 id="_1-2-样式与间距" tabindex="-1">1.2 样式与间距 <a class="header-anchor" href="#_1-2-样式与间距" aria-label="Permalink to &quot;1.2 样式与间距&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">属性</th><th style="text-align:left;">语法 / 示例</th><th style="text-align:left;">详细逻辑</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>column-gap</code></strong></td><td style="text-align:left;"><code>&lt;length&gt; | normal</code><br><code>column-gap: 20px;</code></td><td style="text-align:left;"><strong>列间距</strong>。<br>默认值 <code>normal</code> 通常等于 <code>1em</code>。<br>支持 <code>px</code>, <code>%</code>, <code>em</code> 等。</td></tr><tr><td style="text-align:left;"><strong><code>column-rule</code></strong></td><td style="text-align:left;"><code>width style color</code><br><code>column-rule: 1px solid #ccc;</code></td><td style="text-align:left;"><strong>列分割线</strong>。<br>语法完全等同于 <code>border</code>。<br><strong>注意</strong>：分割线绘制在 Gap 中间，<strong>不占据任何布局空间</strong>。</td></tr></tbody></table><p><img src="'+o+'" alt="Logo" data-zoomable="true"></p><h3 id="_1-3-填充模式-高级" tabindex="-1">1.3 填充模式 (高级) <a class="header-anchor" href="#_1-3-填充模式-高级" aria-label="Permalink to &quot;1.3 填充模式 (高级)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">属性</th><th style="text-align:left;">值</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>column-fill</code></strong></td><td style="text-align:left;"><strong><code>balance</code></strong> (默认)</td><td style="text-align:left;"><strong>平衡填充</strong>。<br>浏览器会尽力保证所有列的高度一致。适合文章阅读。</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>auto</code></td><td style="text-align:left;"><strong>顺序填充</strong>。<br>先填满第一列（需容器有高度限制），再填第二列。<strong>适合做瀑布流</strong>。</td></tr></tbody></table><h2 id="_2-子元素属性-api-item-properties" tabindex="-1">2. 子元素属性 API (Item Properties) <a class="header-anchor" href="#_2-子元素属性-api-item-properties" aria-label="Permalink to &quot;2. 子元素属性 API (Item Properties)&quot;">​</a></h2><p>这些属性设置在多列容器内部的<strong>子元素</strong>（如 <code>h2</code>, <code>p</code>, <code>.card</code>）上。</p><h3 id="_2-1-跨列-spanning" tabindex="-1">2.1 跨列 (Spanning) <a class="header-anchor" href="#_2-1-跨列-spanning" aria-label="Permalink to &quot;2.1 跨列 (Spanning)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">属性</th><th style="text-align:left;">值</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>column-span</code></strong></td><td style="text-align:left;"><code>none</code> (默认)</td><td style="text-align:left;">元素仅在自己的列宽内显示。</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><strong><code>all</code></strong></td><td style="text-align:left;"><strong>横跨所有列</strong>。<br>通常用于标题。元素会截断内容流，该元素之前的内容在上方平衡分列，之后的内容在下方重新分列。</td></tr></tbody></table><p><img src="'+i+`" alt="Logo" data-zoomable="true"></p><h3 id="_2-2-断裂控制-fragmentation" tabindex="-1">2.2 断裂控制 (Fragmentation) <a class="header-anchor" href="#_2-2-断裂控制-fragmentation" aria-label="Permalink to &quot;2.2 断裂控制 (Fragmentation)&quot;">​</a></h3><p>控制元素如何在列之间分割（防止图片被切成两半）。</p><table tabindex="0"><thead><tr><th style="text-align:left;">属性</th><th style="text-align:left;">值</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>break-inside</code></strong></td><td style="text-align:left;"><code>auto</code> (默认)</td><td style="text-align:left;">允许在元素内部断开。</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><strong><code>avoid</code></strong></td><td style="text-align:left;"><strong>禁止断开</strong>。<br>保持元素完整性。做瀑布流卡片时<strong>必加</strong>。</td></tr><tr><td style="text-align:left;"><code>break-before</code></td><td style="text-align:left;"><code>column</code></td><td style="text-align:left;">强制该元素位于新的一列的顶端。</td></tr><tr><td style="text-align:left;"><code>break-after</code></td><td style="text-align:left;"><code>column</code></td><td style="text-align:left;">强制该元素之后开启新的一列。</td></tr></tbody></table><blockquote><p><strong>兼容性提示</strong>：为了兼容旧版浏览器（如老 Webkit），建议同时加上 <code>-webkit-column-break-inside: avoid;</code> 和 <code>page-break-inside: avoid;</code>。</p></blockquote><h2 id="_3-常见问题-faq-与-故障排除" tabindex="-1">3. 常见问题 (FAQ) 与 故障排除 <a class="header-anchor" href="#_3-常见问题-faq-与-故障排除" aria-label="Permalink to &quot;3. 常见问题 (FAQ) 与 故障排除&quot;">​</a></h2><h3 id="_3-1-瀑布流的卡片被-腰斩-切成两半-怎么办" tabindex="-1">3.1 瀑布流的卡片被“腰斩”（切成两半）怎么办？ <a class="header-anchor" href="#_3-1-瀑布流的卡片被-腰斩-切成两半-怎么办" aria-label="Permalink to &quot;3.1 瀑布流的卡片被“腰斩”（切成两半）怎么办？&quot;">​</a></h3><p><strong>现象</strong>：一张卡片的上半部分在第一列底部，下半部分在第二列顶部。</p><p><strong>原因</strong>：浏览器默认允许内容为了填满列而在任意位置断开。</p><p><strong>解决方案</strong>：</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">.card</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  break-inside</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">avoid</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* 标准 */</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -webkit-column-break-inside</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">avoid</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* Chrome/Safari 旧版 */</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  page-break-inside</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">avoid</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* Firefox 旧版 */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  </span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  /* 有时候加上这个能解决极个别渲染 bug */</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  display</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">inline-block</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  width</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">100</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">%</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="_3-2-瀑布流顶部有莫名其妙的空白" tabindex="-1">3.2 瀑布流顶部有莫名其妙的空白？ <a class="header-anchor" href="#_3-2-瀑布流顶部有莫名其妙的空白" aria-label="Permalink to &quot;3.2 瀑布流顶部有莫名其妙的空白？&quot;">​</a></h3><p><strong>现象</strong>：第一列或某一列的第一个元素，并没有顶格对齐，而是往下掉了一点。</p><p><strong>原因</strong>：<strong>Margin Collapse (外边距合并)</strong>。子元素的 <code>margin-top</code> 穿透了父容器，或者因为分列计算导致基线对齐异常。</p><p><strong>解决方案</strong>：</p><ol><li><strong>推荐</strong>：给父容器触发 BFC。<div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">.container</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">overflow</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">hidden</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; }</span></span></code></pre></div></li><li>将子元素的 <code>margin</code> 改为 <code>padding</code>。</li></ol><h3 id="_3-3-column-span-all-导致下面的内容错乱" tabindex="-1">3.3 <code>column-span: all</code> 导致下面的内容错乱？ <a class="header-anchor" href="#_3-3-column-span-all-导致下面的内容错乱" aria-label="Permalink to &quot;3.3 \`column-span: all\` 导致下面的内容错乱？&quot;">​</a></h3><p><strong>限制</strong>：<code>column-span: all</code> 的元素必须是<strong>块级元素</strong>，且它是文档流的一部分。 如果在该元素之前的列填充高度计算出现小数点误差，可能会导致视觉上的错位。</p><p><strong>注意</strong>：<code>column-span</code> 不能被包含在另一个块级上下文中（例如，如果父容器是 <code>display: flex</code>，里面的子元素再用 <code>column-span</code> 可能会失效）。</p><h3 id="_3-4-为什么设置了-column-count-3-但只显示了-1-列" tabindex="-1">3.4 为什么设置了 <code>column-count: 3</code> 但只显示了 1 列？ <a class="header-anchor" href="#_3-4-为什么设置了-column-count-3-但只显示了-1-列" aria-label="Permalink to &quot;3.4 为什么设置了 \`column-count: 3\` 但只显示了 1 列？&quot;">​</a></h3><p><strong>原因</strong>：容器宽度太窄了。 如果你同时设置了 <code>column-width</code> 和 <code>column-count</code>（或者使用了 <code>columns</code> 简写），<code>column-width</code> 的优先级其实是作为一个“下限”存在的。</p><p><strong>逻辑</strong>：如果 <code>容器宽度 / 3</code> 小于 <code>column-width</code> 设定的最小值，浏览器就会减少列数，以保证每列的宽度足够。</p><h3 id="_3-5-怎么给每一列添加背景色" tabindex="-1">3.5 怎么给每一列添加背景色？ <a class="header-anchor" href="#_3-5-怎么给每一列添加背景色" aria-label="Permalink to &quot;3.5 怎么给每一列添加背景色？&quot;">​</a></h3><p><strong>做不到</strong>。 CSS Multi-column 无法直接给“列”这个概念添加背景。内容是流动的，并没有物理上的“第一列 DOM 元素”。</p><p><strong>替代方案</strong>：只能给<strong>子元素</strong>添加背景，或者给父容器加一个条纹背景图 (<code>linear-gradient</code>) 来模拟列背景。</p><h3 id="_3-6-阴影-box-shadow-被切断了" tabindex="-1">3.6 阴影 (<code>box-shadow</code>) 被切断了？ <a class="header-anchor" href="#_3-6-阴影-box-shadow-被切断了" aria-label="Permalink to &quot;3.6 阴影 (\`box-shadow\`) 被切断了？&quot;">​</a></h3><p><strong>现象</strong>：卡片右侧有阴影，但在列的边缘被切掉了。</p><p><strong>原因</strong>：多列容器默认的裁剪行为。</p><p><strong>解决方案</strong>：给卡片留出 margin，不要让阴影紧贴列的边缘；或者给容器加 <code>padding</code>。</p>`,45)])])}const b=e(d,[["render",r]]);export{y as __pageData,b as default};
